// 상용직 근태현황 조회
scwin.f_Retrieve = async function () {
  // 검색조건 필수 입력 체크
  if (!(await $c.gus.cfValidate($p, [acb_lobranCd, ica_stdYm]))) {
    return;
  }
  var dateCheck = "";
  var dateCheck = ica_stdYm.getValue();
  var enddate_Check = ica_endYm.getValue();
  var dateSearchCheck = dateCheck.slice(-2);
  var monthSearchCheck_std = dateCheck.substring(0, 6);
  var monthSearchCheck_end = enddate_Check.substring(0, 6);
  if (dateSearchCheck !== "01") {
    await $c.win.alert($p, "작업시작일 1일부터 조회하실 수 있습니다.");
  } else if (monthSearchCheck_std != monthSearchCheck_end) {
    await $c.win.alert($p, "작업시작일과 작업 종료일의 연도와 월이 같아야합니다.");
  } else {
    scwin.insertCnt = 0;
    $c.sbm.execute($p, sbm_retrieve);
  }
};

